def merge_sort(collection):
    def merge(left, right):
        left_index, right_index = 0, 0
        left_len, right_len = len(left), len(right)
        merged = []
        while left_index < left_len and right_index < right_len:
            if left[left_index] <= right[right_index]:
                merged.append(left[left_index])
                left_index += 1
            else:
                merged.append(right[right_index])
                right_index += 1
        if left_index == left_len:
            merged.extend(right[right_index:])
        else:
            merged.extend(left[left_index:])
        return merged
    if len(collection) <= 1:
        return collection
    mid = len(collection) // 2
    return merge(merge_sort(collection[:mid]), merge_sort(collection[mid:]))

def partition(items, begin, end):
    pivot = items[begin]
    i = begin + 1
    for j in range(begin + 1, end):
        if items[j] < pivot:
            items[i], items[j] = items[j], items[i]
            i += 1
    items[begin], items[i - 1] = items[i - 1], items[begin]
    return i - 1
def quick_sort(items, begin=0, end=None):
    if end is None: end = len(items)
    if begin >= end: return items
    p = partition(items, begin, end)
    quick_sort(items, begin, p)
    quick_sort(items, p + 1, end)
    return items

class Node:
    def __init__(self, data):
        self.data, self.left, self.right = data, None, None
class BinarySearchTree:
    def __init__(self): self.root = None
    def insert(self, data):
        if not self.root: self.root = Node(data)
        else: self._insert_recursive(self.root, data)
    def _insert_recursive(self, node, data):
        if data < node.data:
            if node.left: self._insert_recursive(node.left, data)
            else: node.left = Node(data)
        else:
            if node.right: self._insert_recursive(node.right, data)
            else: node.right = Node(data)

import heapq
def dijkstra(graph, start):
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    pq = [(0, start)]
    while pq:
        curr_dist, curr_node = heapq.heappop(pq)
        if curr_dist > distances[curr_node]: continue
        for neighbor, weight in graph[curr_node].items():
            distance = curr_dist + weight
            if distance < distances[neighbor]:
                distances[neighbor] = distance
                heapq.heappush(pq, (distance, neighbor))
    return distances

def heapify(unsorted, index, heap_size):
    largest = index
    left_index = 2 * index + 1
    right_index = 2 * index + 2
    if left_index < heap_size and unsorted[left_index] > unsorted[largest]:
        largest = left_index
    if right_index < heap_size and unsorted[right_index] > unsorted[largest]:
        largest = right_index
    if largest != index:
        unsorted[largest], unsorted[index] = unsorted[index], unsorted[largest]
        heapify(unsorted, largest, heap_size)
def heap_sort(unsorted):
    n = len(unsorted)
    for i in range(n // 2 - 1, -1, -1):
        heapify(unsorted, i, n)
    for i in range(n - 1, 0, -1):
        unsorted[0], unsorted[i] = unsorted[i], unsorted[0]
        heapify(unsorted, 0, i)
    return unsorted

def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        for j in range(0, n-i-1):
            if arr[j] > arr[j+1]:
                arr[j], arr[j+1] = arr[j+1], arr[j]
    return arr

def selection_sort(collection):
    length = len(collection)
    for i in range(length - 1):
        least = i
        for k in range(i + 1, length):
            if collection[k] < collection[least]:
                least = k
        collection[least], collection[i] = collection[i], collection[least]
    return collection

def insertion_sort(arr):
    for i in range(1, len(arr)):
        key = arr[i]
        j = i - 1
        while j >= 0 and key < arr[j]:
            arr[j + 1] = arr[j]
            j -= 1
        arr[j + 1] = key
    return arr

def depth_first_search(graph, start, visited=None):
    if visited is None:
        visited = set()
    visited.add(start)
    for next in graph[start] - visited:
        depth_first_search(graph, next, visited)
    return visited

def topological_sort(graph):
    visited = set()
    stack = []
    def dfs(u):
        visited.add(u)
        if u in graph:
            for v in graph[u]:
                if v not in visited: dfs(v)
        stack.insert(0, u)
    for u in graph:
        if u not in visited: dfs(u)
    return stack

parent = dict()
rank = dict()
def make_set(vertice):
    parent[vertice] = vertice
    rank[vertice] = 0
def find(vertice):
    if parent[vertice] != vertice:
        parent[vertice] = find(parent[vertice])
    return parent[vertice]
def union(v1, v2):
    root1 = find(v1)
    root2 = find(v2)
    if root1 != root2:
        if rank[root1] > rank[root2]: parent[root2] = root1
        else:
            parent[root1] = root2
            if rank[root1] == rank[root2]: rank[root2] += 1

import heapq
def prim(graph, start):
    mst = []
    visited = set([start])
    edges = [(cost, start, to) for to, cost in graph[start].items()]
    heapq.heapify(edges)
    while edges:
        cost, frm, to = heapq.heappop(edges)
        if to not in visited:
            visited.add(to)
            mst.append((frm, to, cost))
            for to_next, cost2 in graph[to].items():
                if to_next not in visited: heapq.heappush(edges, (cost2, to, to_next))
    return mst

def count_components(n, edges):
    parent = list(range(n))
    def find(i):
        if parent[i] == i: return i
        parent[i] = find(parent[i])
        return parent[i]
    for i, j in edges:
        root_i, root_j = find(i), find(j)
        if root_i != root_j:
            parent[root_i] = root_j
            n -= 1
    return n

