class AVLTree:
    def get_height(self, node): return node.height if node else 0
    def get_balance(self, node): return self.get_height(node.left) - self.get_height(node.right) if node else 0
    def rotate_right(self, y):
        x = y.left; T2 = x.right
        x.right = y; y.left = T2
        y.height = 1 + max(self.get_height(y.left), self.get_height(y.right))
        x.height = 1 + max(self.get_height(x.left), self.get_height(x.right))
        return x

class BinaryHeap:
    def __init__(self): self.heap_list = [0]; self.current_size = 0
    def perc_up(self, i):
        while i // 2 > 0:
            if self.heap_list[i] < self.heap_list[i // 2]:
                self.heap_list[i // 2], self.heap_list[i] = self.heap_list[i], self.heap_list[i // 2]
            i = i // 2
    def insert(self, k):
        self.heap_list.append(k); self.current_size += 1; self.perc_up(self.current_size)

class TrieNode:
    def __init__(self): self.nodes = {}; self.is_leaf = False
class Trie:
    def __init__(self): self.root = TrieNode()
    def insert(self, word):
        curr = self.root
        for char in word:
            if char not in curr.nodes: curr.nodes[char] = TrieNode()
            curr = curr.nodes[char]
        curr.is_leaf = True
    def search(self, word):
        curr = self.root
        for char in word:
            if char not in curr.nodes: return False
            curr = curr.nodes[char]
        return curr.is_leaf

class SegmentTree:
    def __init__(self, arr):
        self.n = len(arr); self.tree = [0] * (2 * self.n)
        for i in range(self.n): self.tree[self.n + i] = arr[i]
        for i in range(self.n - 1, 0, -1): self.tree[i] = self.tree[2 * i] + self.tree[2 * i + 1]
    def update(self, i, val):
        i += self.n; self.tree[i] = val
        while i > 1:
            self.tree[i // 2] = self.tree[i] + self.tree[i ^ 1]
            i //= 2

class UnionFind:
    def __init__(self, n): self.ids = list(range(n)); self.cnt = n
    def find(self, p):
        while p != self.ids[p]:
            self.ids[p] = self.ids[self.ids[p]]; p = self.ids[p]
        return p
    def union(self, p, q):
        i, j = self.find(p), self.find(q)
        if i == j: return
        self.ids[i] = j; self.cnt -= 1

