    num1, num2 = 12, 18
    print(f"LCM of {num1} and {num2}: {lcm(num1, num2)}")  # Output: 36

class Stack:
    """
    A Stack data structure following LIFO (Last In, First Out) principle.
    """

    def __init__(self):
        # Internal list to store stack elements
        self._items = []

    def push(self, item) -> None:
        """Adds an item to the top of the stack."""
        self._items.append(item)

    def pop(self):
        """Removes and returns the top item from the stack."""
        if self.is_empty():
            raise IndexError("pop from an empty stack")
        return self._items.pop()

    def peek(self):
        """Returns the top item without removing it."""
        if self.is_empty():
            raise IndexError("peek from an empty stack")
        return self._items[-1]

    def is_empty(self) -> bool:
        """Returns True if the stack is empty."""
        return len(self._items) == 0

    def size(self) -> int:
        """Returns the number of items in the stack."""
        return len(self._items)

    def __repr__(self) -> str:
        return f"Stack({self._items})"

# Example usage
if __name__ == "__main__":
    s = Stack()
    s.push(10)
    s.push(20)
    s.push(30)
    print(s)           # Stack([10, 20, 30])
    print(s.pop())     # 30
    print(s.peek())    # 20

from collections import deque

class Queue:
    """
    A Queue data structure following FIFO (First In, First Out) principle.
    Uses collections.deque for efficient O(1) enqueue and dequeue operations.
    """

    def __init__(self):
        # Use deque for efficient front-removal
        self._data = deque()

    def enqueue(self, item) -> None:
        """Adds an item to the rear of the queue."""
        self._data.append(item)

    def dequeue(self):
        """Removes and returns the item from the front of the queue."""
        if self.is_empty():
            raise IndexError("dequeue from an empty queue")
        return self._data.popleft()

    def front(self):
        """Returns the front item without removing it."""
        if self.is_empty():
            raise IndexError("front from an empty queue")
        return self._data[0]

    def is_empty(self) -> bool:
        """Returns True if the queue is empty."""
        return len(self._data) == 0

    def size(self) -> int:
        """Returns the number of elements in the queue."""
        return len(self._data)

# Example usage
if __name__ == "__main__":
    q = Queue()
    q.enqueue("first")
    q.enqueue("second")
    q.enqueue("third")
    print(q.dequeue())  # first
    print(q.front())    # second
    print(q.size())     # 2

class Node:
    """Represents a single node in a linked list."""

    def __init__(self, data):
        self.data = data   # Data stored in the node
        self.next = None   # Pointer to the next node

class LinkedList:
    """
    A singly linked list implementation with basic operations.
    """

    def __init__(self):
        self.head = None  # Head node of the list

    def insert_at_end(self, data) -> None:
        """Inserts a new node at the end of the list."""
        new_node = Node(data)
        if self.head is None:
            self.head = new_node
            return
        current = self.head
        while current.next:
            current = current.next
        current.next = new_node

    def delete_node(self, data) -> bool:
        """Deletes the first node containing the given data."""
        if self.head is None:
            return False
        if self.head.data == data:
            self.head = self.head.next
            return True
        current = self.head
        while current.next:
            if current.next.data == data:
                current.next = current.next.next
                return True
            current = current.next
        return False

    def display(self) -> list:
        """Returns all node data as a list."""
        result = []
        current = self.head
        while current:
            result.append(current.data)
            current = current.next
        return result

    def __len__(self) -> int:
        count = 0
        current = self.head
        while current:
            count += 1
            current = current.next
        return count

# Example usage
if __name__ == "__main__":
    ll = LinkedList()
    for val in [10, 20, 30, 40]:
        ll.insert_at_end(val)
    print(ll.display())         # [10, 20, 30, 40]
    ll.delete_node(20)
    print(ll.display())         # [10, 30, 40]

class Deque:
    """
    A Double-Ended Queue (Deque) that supports insertion and deletion
    from both the front and the rear.
    """

    def __init__(self):
        self._items = []  # Internal list to hold elements

    def add_front(self, item) -> None:
        """Inserts an item at the front of the deque."""
        self._items.insert(0, item)

    def add_rear(self, item) -> None:
        """Inserts an item at the rear of the deque."""
        self._items.append(item)

    def remove_front(self):
        """Removes and returns the item from the front."""
        if self.is_empty():
            raise IndexError("remove_front from an empty deque")
        return self._items.pop(0)

    def remove_rear(self):
        """Removes and returns the item from the rear."""
        if self.is_empty():
            raise IndexError("remove_rear from an empty deque")
        return self._items.pop()

    def peek_front(self):
        """Returns the front item without removing it."""
        if self.is_empty():
            return None
        return self._items[0]

    def peek_rear(self):
        """Returns the rear item without removing it."""
        if self.is_empty():
            return None
        return self._items[-1]

    def is_empty(self) -> bool:
        """Returns True if the deque is empty."""
        return len(self._items) == 0

    def size(self) -> int:
        """Returns the number of elements in the deque."""
        return len(self._items)

# Example usage
if __name__ == "__main__":
    dq = Deque()
    dq.add_rear(10)
    dq.add_front(5)
    dq.add_rear(20)
    print(dq.remove_front())  # 5
    print(dq.remove_rear())   # 20
    print(dq.size())          # 1

def gcd_stein(a: int, b: int) -> int:
    """
    Computes the GCD of two non-negative integers using the binary GCD
    (Stein's) algorithm, which avoids division operations.

    Args:
        a: First non-negative integer.
        b: Second non-negative integer.

    Returns:
        The Greatest Common Divisor of a and b.
    """
    if a == 0:
        return b
    if b == 0:
        return a
    if a == b:
        return a

    # Both even
    if a % 2 == 0 and b % 2 == 0:
        return 2 * gcd_stein(a // 2, b // 2)
    # a is even
    if a % 2 == 0:
        return gcd_stein(a // 2, b)
    # b is even
    if b % 2 == 0:
        return gcd_stein(a, b // 2)
    # Both odd
    if a > b:
        return gcd_stein((a - b) // 2, b)
    return gcd_stein((b - a) // 2, a)

# Example usage
if __name__ == "__main__":
    print(gcd_stein(48, 18))  # 6
    print(gcd_stein(100, 75)) # 25

def caesar_cipher_encode(text: str, shift: int) -> str:
    """Encrypts text using the Caesar Cipher."""
    encoded = []
    for char in text:
        if char.isalpha():
            offset = ord('A') if char.isupper() else ord('a')
            encoded.append(chr((ord(char) - offset + shift) % 26 + offset))
        else:
            encoded.append(char)
    return ''.join(encoded)

def caesar_cipher_decode(text: str, shift: int) -> str:
    """Decrypts text encrypted with Caesar Cipher."""
    return caesar_cipher_encode(text, -shift)

def brute_force_caesar(ciphertext: str) -> None:
    """Attempts all 26 possible Caesar Cipher shifts."""
    print("Brute force results:")
    for shift in range(26):
        decoded = caesar_cipher_decode(ciphertext, shift)
        print(f"  Shift {shift:2d}: {decoded}")

# Example usage
if __name__ == "__main__":
    original = "The quick brown fox"
    shift = 13
    encrypted = caesar_cipher_encode(original, shift)
    decrypted = caesar_cipher_decode(encrypted, shift)
    print(f"Original:  {original}")
    print(f"Encrypted: {encrypted}")
    print(f"Decrypted: {decrypted}")

class Node:
    """A single node in a doubly linked list."""

    def __init__(self, data):
        self.data = data
        self.prev = None
        self.next = None


class DoublyLinkedList:
    """
    A doubly linked list supporting O(1) insertions at both ends
    and O(n) arbitrary insertions/deletions.
    """

    def __init__(self):
        """Initialize an empty doubly linked list."""
        self.head = None
        self.tail = None
        self._length = 0

    def append(self, data) -> None:
        """Append a new node at the tail."""
        node = Node(data)
        if self.tail is None:
            self.head = self.tail = node
        else:
            node.prev = self.tail
            self.tail.next = node
            self.tail = node
        self._length += 1

    def prepend(self, data) -> None:
        """Insert a new node at the head."""
        node = Node(data)
        if self.head is None:
            self.head = self.tail = node
        else:
            node.next = self.head
            self.head.prev = node
            self.head = node
        self._length += 1

    def remove(self, data) -> bool:
        """Remove first occurrence of data. Returns True if found."""
        current = self.head
        while current:
            if current.data == data:
                if current.prev:
                    current.prev.next = current.next
                else:
                    self.head = current.next
                if current.next:
                    current.next.prev = current.prev
                else:
                    self.tail = current.prev
                self._length -= 1
                return True
            current = current.next
        return False

    def to_list(self) -> list:
        """Convert to a Python list for easy inspection."""
        result, current = [], self.head
        while current:
            result.append(current.data)
            current = current.next
        return result

    def __len__(self) -> int:
        return self._length


if __name__ == "__main__":
    dll = DoublyLinkedList()
    for v in [10, 20, 30]:
        dll.append(v)
    dll.prepend(5)
    print(dll.to_list())   # [5, 10, 20, 30]
    dll.remove(20)
    print(dll.to_list())   # [5, 10, 30]
    print(len(dll))        # 3

from typing import List, Dict, Union
import math

Number = Union[int, float]


def mean(data: List[Number]) -> float:
    """Return the arithmetic mean of a non-empty list of numbers."""
    if not data:
        raise ValueError("Cannot compute mean of an empty dataset")
    return sum(data) / len(data)


def median(data: List[Number]) -> float:
    """
    Return the median of a list of numbers.

    For an even-length list the median is the average of the two
    middle values; for odd-length it is the single middle value.
    """
    if not data:
        raise ValueError("Cannot compute median of an empty dataset")
    sorted_data = sorted(data)
    n = len(sorted_data)
    mid = n // 2
    if n % 2 == 1:
        return float(sorted_data[mid])
    return (sorted_data[mid - 1] + sorted_data[mid]) / 2.0


def mode(data: List[Number]) -> Number:
    """Return the most frequently occurring value in the dataset."""
    if not data:
        raise ValueError("Cannot compute mode of an empty dataset")
    freq: Dict[Number, int] = {}
    for x in data:
        freq[x] = freq.get(x, 0) + 1
    return max(freq, key=freq.get)


def variance(data: List[Number], population: bool = True) -> float:
    """
    Compute variance.

    Args:
        data: List of numeric values.
        population: If True, compute population variance (÷ n);
                    if False, compute sample variance (÷ n-1).
    """
    if not data:
        raise ValueError("Cannot compute variance of an empty dataset")
    m = mean(data)
    n = len(data)
    divisor = n if population else n - 1
    return sum((x - m) ** 2 for x in data) / divisor


def std_deviation(data: List[Number], population: bool = True) -> float:
    """Return the standard deviation of the dataset."""
    return math.sqrt(variance(data, population))


def summary_statistics(data: List[Number]) -> Dict[str, float]:
    """Compute a full set of descriptive statistics for the data."""
    return {
        "n": len(data),
        "mean": mean(data),
        "median": median(data),
        "mode": mode(data),
        "variance": variance(data),
        "std_dev": std_deviation(data),
        "min": min(data),
        "max": max(data),
        "range": max(data) - min(data),
    }


if __name__ == "__main__":
    dataset = [4, 8, 6, 5, 3, 2, 8, 9, 2, 5]
    stats = summary_statistics(dataset)
    for name, value in stats.items():
        print(f"  {name:10s}: {value}")
